import { useState, useEffect } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import axios from 'axios';

const CATEGORIES = ['All', 'Technology', 'Health', 'Education', 'Environment', 'Art', 'Social Impact', 'Finance', 'Other'];

export default function BrowseProjects() {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [searchParams] = useSearchParams();
  const [category, setCategory] = useState(searchParams.get('category') || 'All');
  const [sort, setSort] = useState('newest');

  useEffect(() => {
    setLoading(true);
    const params = new URLSearchParams();
    if (category !== 'All') params.set('category', category);
    if (search) params.set('search', search);
    if (sort !== 'newest') params.set('sort', sort);

    axios.get(`/api/projects?${params}`)
      .then(r => setProjects(r.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, [category, search, sort]);

  return (
    <div style={{ background: '#0a0d1a', minHeight: '100vh' }} className="px-6 py-10">
      <div className="max-w-6xl mx-auto">
        <h1 style={{ fontFamily: 'Syne, sans-serif' }} className="text-3xl font-bold mb-8">Browse Projects</h1>

        {/* Filters */}
        <div className="flex flex-wrap gap-4 mb-8">
          <input value={search} onChange={e => setSearch(e.target.value)}
            style={{ background: '#111827', border: '1px solid #1f2937', color: 'white' }}
            className="px-4 py-2.5 rounded-xl text-sm flex-1 max-w-xs focus:outline-none focus:border-teal-500"
            placeholder="Search projects..." />

          <select value={sort} onChange={e => setSort(e.target.value)}
            style={{ background: '#111827', border: '1px solid #1f2937', color: '#9ca3af' }}
            className="px-4 py-2.5 rounded-xl text-sm">
            <option value="newest">Newest</option>
            <option value="funding">Most Funded</option>
          </select>
        </div>

        {/* Category pills */}
        <div className="flex flex-wrap gap-2 mb-8">
          {CATEGORIES.map(c => (
            <button key={c} onClick={() => setCategory(c)}
              style={{
                background: category === c ? '#00d4aa' : '#111827',
                color: category === c ? '#0a0d1a' : '#9ca3af',
                border: category === c ? 'none' : '1px solid #1f2937'
              }}
              className="px-4 py-1.5 rounded-full text-sm font-medium transition-all">
              {c}
            </button>
          ))}
        </div>

        {loading ? (
          <div className="text-center text-gray-500 py-20">Loading projects...</div>
        ) : projects.length === 0 ? (
          <div className="text-center text-gray-500 py-20">No projects found</div>
        ) : (
          <div className="grid grid-cols-3 gap-5">
            {projects.map(p => {
              const pct = Math.min(Math.round((p.currentFunding / p.fundingGoal) * 100), 100);
              return (
                <Link key={p._id} to={`/projects/${p._id}`}
                  style={{ background: '#111827', border: '1px solid #1f2937' }}
                  className="rounded-2xl overflow-hidden hover:border-teal-900 transition-all group">
                  {p.coverImage ? (
                    <img src={p.coverImage} alt={p.title} className="w-full h-40 object-cover" />
                  ) : (
                    <div style={{ background: 'linear-gradient(135deg, #1f2937, #111827)', height: 160 }}
                         className="flex items-center justify-center text-4xl">
                      {p.category === 'Technology' ? '💻' : p.category === 'Health' ? '🏥' :
                       p.category === 'Education' ? '📚' : p.category === 'Environment' ? '🌱' : '✦'}
                    </div>
                  )}
                  <div className="p-5">
                    <span style={{ background: '#1f2937', color: '#9ca3af' }}
                          className="text-xs px-2 py-0.5 rounded-full">{p.category}</span>
                    <h3 className="font-bold mt-2 mb-1 group-hover:text-teal-400 transition-colors line-clamp-1">
                      {p.title}
                    </h3>
                    <p className="text-gray-400 text-xs line-clamp-2 mb-4">{p.description}</p>

                    <div style={{ background: '#0a0d1a', height: 6, borderRadius: 3 }} className="mb-2">
                      <div style={{ background: '#00d4aa', width: `${pct}%`, height: '100%', borderRadius: 3 }} />
                    </div>
                    <div className="flex justify-between text-xs">
                      <span style={{ color: '#00d4aa' }} className="font-semibold">{pct}% funded</span>
                      <span className="text-gray-500">${p.fundingGoal?.toLocaleString()} goal</span>
                    </div>
                  </div>
                </Link>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}
